      }
    } else if (path == 'payment' && uri.pathSegments.length >= 2) {
      final action = uri.pathSegments[1];
      if (action == 'confirm') {
        parameters['action'] = 'confirm';
        if (queryParameters.containsKey('transactionId')) {
