          if (_isValidId(txId)) {
            parameters['transactionId'] = _sanitize(txId);
          } else {
            return null;
          }
        }
      } else {
        return null;
      }
    } else {
      return null;
    }

    final sanitizedQueryParams = <String, String>{};
    queryParameters.forEach((key, value) {
      sanitizedQueryParams[_sanitize(key)] = _sanitize(value);
    });

    return DeepLinkRoute(
      path: path,
      parameters: parameters,
      queryParameters: sanitizedQueryParams,
    );
  }

  static bool _isValidId(String id) {
    final idPattern = RegExp(r'^[a-zA-Z0-9_\-]+$');
    return idPattern.hasMatch(id) && id.length <= 100;
  }

  static String _sanitize(String input) {
    return input
        .replaceAll(RegExp(r'[<>"\']'), '')
        .replaceAll(RegExp(r'[\x00-\x1F\x7F]'), '');
