          }
          break;

        case 'payment':
          final action = route.parameters['action'];
          if (action == 'confirm') {
            final transactionId = route.parameters['transactionId'];
            await Navigator.of(context).pushNamed(
              '/payment/confirm',
              arguments: {
                'transactionId': transactionId,
                'queryParams': route.queryParameters,
              },
            );
          }
          break;

        default:
          debugPrint('Unknown deep link path: ${route.path}');
      }
    } catch (e) {
      debugPrint('Navigation error: $e');
    }
  }
}

